#include <cstdio>
#include <cstdlib>
#include <omp.h>

#define N 1024
#define T 100

void stencil_1d(float *in, float *out, int n, int t) {
    for (int time = 0; time < t; time++) {
        #pragma omp parallel for
        for (int i = 1; i < n - 1; i++) {
            out[i] = 0.33333f * (in[i - 1] + in[i] + in[i + 1]);
        }
        // Swap pointers
        float *temp = in;
        in = out;
        out = temp;
    }
}

int main() {
    float *in = (float*)malloc(N * sizeof(float));
    float *out = (float*)malloc(N * sizeof(float));

    for (int i = 0; i < N; i++) {
        in[i] = (float)i;
        out[i] = 0.0f;
    }

    stencil_1d(in, out, N, T);

    // Print some output to verify
    for (int i = 0; i < 10; i++) {
        printf("%f ", in[i]);
    }
    printf("\n");

    free(in);
    free(out);
    return 0;
}
